import type { MapRef } from '@vis.gl/react-maplibre';

export const attachImageToMap = (
  map: MapRef,
  bitmap: ImageBitmap | HTMLImageElement,
  iconName: string,
  sdf = true,
) => {
  const pixelRatio = devicePixelRatio;
  try {
    if (!map.hasImage(iconName)) {
      map.addImage(iconName, bitmap, { sdf: sdf, pixelRatio });
    } else {
      // Update doesn't work until you make some move in the map, so we need to
      // remove it and add it to make the render right away
      map.removeImage(iconName);
      map.addImage(iconName, bitmap, { sdf: sdf, pixelRatio });
    }
  } catch (error: unknown) {
    // If the whole map is unloaded, but the load events on some images are fired, it will trigger the `addImage`
    // on the map reference. Since the map is already unloaded, it will no longer be able to handle the internal getImage
    // call.
    if (error instanceof Error) {
      return;
    }
    throw error;
  }
};
